sql:
SELECT funding_id, funding_number, pub_id, type, funding_amount,
       (SELECT MAX(funding_amount) FROM funding) AS max_funding
FROM funding;

SELECT keyword_id, COUNT(pub_id) AS pub_count
FROM publication_keywords
GROUP BY keyword_id;

SELECT name, organization, json_array_length(research_interests) AS research_interest_count
FROM authors
WHERE author_id = 0;

SELECT AVG(funding_amount) AS average_funding_amount
FROM funding
WHERE status = 'Completed';

